import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
    };

    const getMenuStyle = (menuId) => ({
        background: 'none', border: 'none',
        color: hoveredMenu === menuId ? '#ea580c' : '#fff',
        fontWeight: '700', cursor: 'pointer', fontSize: '14px', transition: 'color 0.3s ease'
    });

    return (
        <nav style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '20px 5%', background: '#0c0a09', borderBottom: '1px solid #262626' }}>
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h2 style={{ color: '#fef3c7', margin: 0, fontSize: '20px' }}>PasukanYerusSolo</h2>
            </div>

            <div className="nav-menu" style={{ display: 'flex', gap: '25px' }}>
                <button style={getMenuStyle('home')} onClick={() => navigateTo('/', 'home')} onMouseEnter={() => setHoveredMenu('home')} onMouseLeave={() => setHoveredMenu(null)}>Beranda</button>
                <button style={getMenuStyle('lowongan')} onClick={() => navigateTo('/eksplorasi', 'lowongan')} onMouseEnter={() => setHoveredMenu('lowongan')} onMouseLeave={() => setHoveredMenu(null)}>Lowongan</button>

                {/* Menu hanya muncul untuk akun dengan role Perusahaan */}
                {isAuthenticated && userRole === 'Perusahaan' && (
                    <>
                        <button onClick={() => navigate('/hrd/dashboard')}>Dashboard</button>
                        <button onClick={() => navigate('/hrd/branding')}>Branding</button>
                    </>
                )}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                {isAuthenticated ? (
                    <button onClick={handleLogout} style={{ padding: '6px 16px', borderRadius: '20px', border: '1px solid #ef4444', color: '#ef4444', cursor: 'pointer', background: 'transparent' }}>Keluar</button>
                ) : (
                    <button onClick={() => navigate('/login')} style={{ padding: '6px 16px', borderRadius: '20px', border: '1px solid #ea580c', color: '#ea580c', cursor: 'pointer', background: 'transparent' }}>Login</button>
                )}
            </div>
            <style>{`@media (max-width: 768px) { .nav-menu { display: none !important; } }`}</style>
        </nav>
    );
};

export default Navbar;
